# Check and advance phases - runs every 30 minutes
import asyncio

async def check_phases():
    try:
        # Read current phase status
        phase_data = await self.read_file(path="~/openclaw-core/data/phase_status.json")

        # Check what phases need work
        phases = ["phase1", "phase2", "phase3", "phase4", "phase5"]

        for phase in phases:
            # Check if phase needs completion
            tasks = []
            if phase == "phase4":
                tasks = [
                    {"manager": "alpha", "task": "Complete Phase 4 agent building and testing", "priority": 1},
                    {"manager": "beta", "task": "Implement remaining Phase 4 coding tasks", "priority": 1},
                    {"manager": "gamma", "task": "Research and validate Phase 4 completion criteria", "priority": 1}
                ]
            elif phase == "phase5":
                tasks = [
                    {"manager": "alpha", "task": "Begin Phase 5: System optimization", "priority": 2},
                    {"manager": "beta", "task": "Performance tuning for Phase 5", "priority": 2}
                ]

            if tasks:
                await self.batch_delegate(tasks=tasks)

        # Update phase status in Obsidian
        await self.knowledge_query(
            action="write",
            path="Phase Tracker.md",
            content=f"## Phase Status Update\n\nLast checked: {datetime.now().isoformat()}\n\nPhase 4: In Progress\nPhase 5: Pending\n",
            tags=["phases", "tracking"]
        )

    except Exception as e:
        await self.memory_store(
            content=f"Phase checker error: {str(e)}",
            category="error",
            importance=0.8
        )

await check_phases()
